namespace Cryptography.Tests.Dsa.MlDsa;

using CryptoHives.Foundation.Security.Cryptography.Dsa;
using NUnit.Framework;
using System;

/// <summary>
/// Known-answer tests for HashML-DSA (FIPS 204 §5.4) (pre-hash variant) using official NIST ACVP test vectors.
/// </summary>
/// <remarks>
/// Vectors are curated from the NIST ACVP-Server sigGen/sigVer validation files
/// (ML-DSA-sigGen/sigVer-FIPS204, https://github.com/usnistgov/ACVP-Server), external interface,
/// preHash groups. The pre-hash digest PH(M) is recomputed from the vector's message
/// with this library's own hash implementations, so these tests also cross-check the
/// OID-to-hash binding end-to-end. Test case ids (tcId) reference the original files.
/// </remarks>
[TestFixture]
[Parallelizable(ParallelScope.All)]
public class MlDsaPreHashAcvpTests
{

    private static readonly object[] SigGenVectors =
    [
        // ML-DSA-44, ACVP sigGen (preHash, deterministic) tcId 25, PH = SHA2-224
        new object[] { "ML-DSA-44", 25, "SHA2-224", "", "0B", "E52ECDF7333CF5ACE4B3808282", "" },
        // ML-DSA-44, ACVP sigGen (preHash, deterministic) tcId 27, PH = SHA2-512/256
        new object[] { "ML-DSA-44", 27, "SHA2-512/256", "", "98A17B47D0051038DF8CDF929D1FBA851B431C8862480D6F423365205A80692DA50F12565C3EB4DE6454213292E13C0DC8EA6B2EF969B8AAF8D78684E4748D01BF7174D92D8270877116F11BF20547C8B74994E781299F19E93FD8CDC525F4556F1437DAAAF3575CD2ED579882A2EAD1A44BAAD8C9FD15F74B1ECD85DF4274C9AE74BDDDD6EC1461225EE49720EB38B6", "BAC901CEED4C0E5C0C5C9F03B81D55DDCCA12DBD93B172ED915A2A7DC2326CD21D0CDEAC8F50EF2E7A85E596D213810A6450D6041BDBDB9975901EDD7B88E2F2F271173928BA2DA3", "" },
        // ML-DSA-44, ACVP sigGen (preHash, deterministic) tcId 26, PH = SHA2-512
        new object[] { "ML-DSA-44", 26, "SHA2-512", "", "", "", "" },
        // ML-DSA-65, ACVP sigGen (preHash, deterministic) tcId 47, PH = SHA2-384
        new object[] { "ML-DSA-65", 47, "SHA2-384", "", "3B", "", "" },
        // ML-DSA-65, ACVP sigGen (preHash, deterministic) tcId 51, PH = SHA2-512
        new object[] { "ML-DSA-65", 51, "SHA2-512", "", "", "CEF865703ADCACC70FB9EF857EB9F2D2614D946869812DFE5034B0F0FF92C45BEBD35798D4F9", "" },
        // ML-DSA-65, ACVP sigGen (preHash, deterministic) tcId 56, PH = SHA2-512/224
        new object[] { "ML-DSA-65", 56, "SHA2-512/224", "", "", "7421E0C96A6919EC5676C3BEF2CA4CEA22799F5F384FC6E33C472BFA340BECD92604B428843DA3F8A3D66025A39D370CB827F6C5AF8CBF284965070E62BCC2B79C665C29D70411193F4EEBF7770F4844558D", "" },
        // ML-DSA-87, ACVP sigGen (preHash, deterministic) tcId 83, PH = SHA2-224
        new object[] { "ML-DSA-87", 83, "SHA2-224", "", "3A", "8A864ADC41CC54FEA02E8E4E16BDF2CDB0E2DEC52427E6785E02D94067311667E9342498498761D7BDA19EDA61D1BC196DDC80D884CC50AF1E9364A3A3129F3F09F01FD3D75FA931BA639275D6050BC3A57C52077120580907FBF8F2B81B3A501675DF6D946296BFE3F1F8DDD557AA16851DBEDD62", "" },
        // ML-DSA-87, ACVP sigGen (preHash, deterministic) tcId 88, PH = SHA3-224
        new object[] { "ML-DSA-87", 88, "SHA3-224", "", "", "D3C08054203F8CA4F69956666AE91C6C7599961D9D054DC35006507340DAB9063990642917FC", "" },
        // ML-DSA-87, ACVP sigGen (preHash, deterministic) tcId 78, PH = SHA2-512/256
        new object[] { "ML-DSA-87", 78, "SHA2-512/256", "", "", "", "" },
    ];

    private static readonly object[] SigVerVectors =
    [
        // ML-DSA-44, ACVP sigVer (preHash) tcId 16 (valid signature and message - signature should verify successfully), PH = SHA3-384
        new object[] { "ML-DSA-44", 16, true, "SHA3-384", "", "", "2E0BAF0BFF7524FF72975F85B5BE47AEE73C575299E8AB272DE91DAC01CC", "" },
        // ML-DSA-44, ACVP sigVer (preHash) tcId 26 (modified signature - z), PH = SHA2-256
        new object[] { "ML-DSA-44", 26, false, "SHA2-256", "", "7A", "E04B02EA10722D4967FD3FBFA54FD4F950A450", "" },
        // ML-DSA-65, ACVP sigVer (preHash) tcId 51 (valid signature and message - signature should verify successfully), PH = SHAKE-256
        new object[] { "ML-DSA-65", 51, true, "SHAKE-256", "", "", "D6C473BD60227FC2C7E320587B8E827507", "" },
        // ML-DSA-65, ACVP sigVer (preHash) tcId 54 (modified message), PH = SHA2-512
        new object[] { "ML-DSA-65", 54, false, "SHA2-512", "", "7E", "7A691599804D0A2167658427C3AD72EEDF92FE2F4A01F30923974BB90F1DD088F98A38061E0C96B151FC17DBADBD79C5C0998E83E5D72B", "" },
        // ML-DSA-87, ACVP sigVer (preHash) tcId 85 (valid signature and message - signature should verify successfully), PH = SHA2-224
        new object[] { "ML-DSA-87", 85, true, "SHA2-224", "", "", "", "" },
        // ML-DSA-87, ACVP sigVer (preHash) tcId 77 (modified signature - hint), PH = SHA3-512
        new object[] { "ML-DSA-87", 77, false, "SHA3-512", "", "62", "", "" },
    ];

    [Test]
    [TestCaseSource(nameof(SigGenVectors))]
    public void SigGenPreHashDeterministic_MatchesAcvpVector(string parameterSet, int tcId, string hashAlg,
        string skHex, string messageHex, string contextHex, string signatureHex)
    {
        MlDsaParams p = PreHashTestUtil.MlDsaParamsFor(parameterSet);
        (byte[] digest, string oid) = PreHashTestUtil.ComputeDigest(hashAlg, PreHashTestUtil.FromHex(messageHex));

        byte[] prefix = new byte[PreHash.MaxPrefixBytes];
        int prefixLength = PreHash.BuildPrefix(PreHashTestUtil.FromHex(contextHex), oid, prefix);

        byte[] rnd = new byte[MlDsaParams.SignSeedBytes];
        byte[] signature = new byte[p.SignatureBytes];
        MlDsaCore.Sign(p, PreHashTestUtil.FromHex(skHex), prefix.AsSpan(0, prefixLength), digest, rnd, signature);

        Assert.That(signature, Is.EqualTo(PreHashTestUtil.FromHex(signatureHex)),
            $"{parameterSet} tcId {tcId} (PH = {hashAlg}): signature mismatch.");
    }

    [Test]
    [TestCaseSource(nameof(SigVerVectors))]
    public void SigVerPreHash_MatchesAcvpVector(string parameterSet, int tcId, bool expectedValid, string hashAlg,
        string pkHex, string messageHex, string contextHex, string signatureHex)
    {
        using var verifier = MlDsa.ImportPublicKey(PreHashTestUtil.MlDsaAlgorithmFor(parameterSet), PreHashTestUtil.FromHex(pkHex));
        (byte[] digest, string oid) = PreHashTestUtil.ComputeDigest(hashAlg, PreHashTestUtil.FromHex(messageHex));

        bool valid = verifier.VerifyPreHash(digest, PreHashTestUtil.FromHex(signatureHex), oid, PreHashTestUtil.FromHex(contextHex));

        Assert.That(valid, Is.EqualTo(expectedValid), $"{parameterSet} tcId {tcId} (PH = {hashAlg}): verification result mismatch.");
    }
}
